// src/contexts/AuthContext.js
import React, { createContext, useState, useContext, useEffect } from 'react';
import config from '../config/config';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [authError, setAuthError] = useState(null);

  useEffect(() => {
    // Check localStorage on app start
    const savedUser = localStorage.getItem(config.AUTH.USER_KEY);
    const savedToken = localStorage.getItem(config.AUTH.TOKEN_KEY);
    
    if (savedUser && savedToken) {
      try {
        const parsedUser = JSON.parse(savedUser);
        setUser(parsedUser);
      } catch (error) {
        console.error('Error parsing saved user:', error);
        logout();
      }
    }
    setLoading(false);
  }, []);

  // ✅ UPDATED: Accept user and token directly (for your backend)
  const login = async (userData, token) => {
    try {
      setAuthError(null);
      
      if (!userData || !token) {
        throw new Error('Invalid login response');
      }
      
      // Store in localStorage
      localStorage.setItem(config.AUTH.TOKEN_KEY, token);
      localStorage.setItem(config.AUTH.USER_KEY, JSON.stringify(userData));
      setUser(userData);
      
      return { user: userData, token };
      
    } catch (error) {
      setAuthError(error.message || 'Login failed');
      throw error;
    }
  };

  // ✅ Keep the old login function for backward compatibility
  const loginWithCredentials = async (email, password) => {
    try {
      setAuthError(null);
      
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ email, password }),
      });

      const data = await response.json();

      if (response.ok) {
        localStorage.setItem(config.AUTH.TOKEN_KEY, data.access_token);
        localStorage.setItem(config.AUTH.USER_KEY, JSON.stringify(data.user));
        setUser(data.user);
        return data;
      } else {
        throw new Error(data.error || 'Login failed');
      }
    } catch (error) {
      setAuthError(error.message || 'Login failed');
      throw error;
    }
  };

  const register = async (userData) => {
    try {
      setAuthError(null);
      
      const response = await fetch('http://localhost:5000/api/auth/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(userData),
      });

      const data = await response.json();

      if (response.ok) {
        return data;
      } else {
        throw new Error(data.error || 'Registration failed');
      }
    } catch (error) {
      setAuthError(error.message || 'Registration failed');
      throw error;
    }
  };

  const logout = () => {
    localStorage.removeItem(config.AUTH.TOKEN_KEY);
    localStorage.removeItem(config.AUTH.USER_KEY);
    setUser(null);
    setAuthError(null);
    window.location.href = '/';
  };

  const updateProfile = (updatedData) => {
    try {
      const updatedUser = { ...user, ...updatedData };
      localStorage.setItem(config.AUTH.USER_KEY, JSON.stringify(updatedUser));
      setUser(updatedUser);
    } catch (error) {
      console.error('Error updating profile:', error);
    }
  };

  const checkPermission = (permission) => {
    if (!user) return false;
    if (user.role === 'admin') return true;
    return user.permissions?.includes(permission) || false;
  };

  const isCourseAccessible = (courseId) => {
    if (!user) return false;
    if (user.role === 'admin') return true;
    return user.role === 'student' || user.role === 'user';
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      loading, 
      authError,
      login, // ✅ For your current login flow
      loginWithCredentials, // ✅ Alternative method
      register,
      logout,
      updateProfile,
      checkPermission,
      isCourseAccessible,
      isAuthenticated: !!user,
      isAdmin: user?.role === 'admin',
      isStudent: user?.role === 'student' || user?.role === 'user'
    }}>
      {children}
    </AuthContext.Provider>
  );
};
